]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "The Digital Twin is hosted directly on the same Raspberry Pi 4 Model B that hosts the controller, with all libraries installed locally. The system is deployable on‑premises and the code is available open‑source on GitHub for potential cloud deployment via virtual machines or containerised stacks."
